222→        e.stopPropagation();
223→        if(imgRef.current){
224→            imgRef.current.click();
225→        }
226→    }
227→    const handleImageChange = (e) =>{
228→        const file = e.target.files[0];
229→        if(file){
230→            setImageFile(file)
231→            const reader = new FileReader();
232→            reader.onloadend = () =>{
233→                setProfilePreview(reader.result)
234→            }
235→            reader.readAsDataURL(file)
236→        }
237→    }
238→
239→    const slugifyForUsername = (val) =>
240→        String(val || '').toLowerCase().trim().replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
241→
242→    const handleNameChangeForSetup = (e) => {
243→        const newName = e.target.value;
244→        setName(newName);
245→        // Auto-suggest username from name if user hasn't manually edited username
246→        if (!setupUsername || setupUsername === slugifyForUsername(name)) {
247→            const suggested = slugifyForUsername(newName);
248→            setSetupUsername(suggested);
249→            checkUsernameDebounced(suggested);
250→        }
251→    };
252→
253→    const handleUsernameChange = (e) => {
254→        const raw = e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '');
255→        setSetupUsername(raw);
256→        checkUsernameDebounced(raw);
257→    };
258→
259→    const checkUsernameDebounced = (uname) => {
260→        if (usernameCheckTimer.current) clearTimeout(usernameCheckTimer.current);
261→        if (!uname || uname.length < 3) {
262→            setUsernameAvailable(null);
263→            return;
264→        }
265→        setUsernameChecking(true);
266→        usernameCheckTimer.current = setTimeout(async () => {
267→            try {
268→                const result = await checkUsernameAvailability(uname);
269→                setUsernameAvailable(result.available);
270→            } catch {
271→                setUsernameAvailable(null);
272→            } finally {
273→                setUsernameChecking(false);
274→            }
275→        }, 400);
276→    };
277→
278→    const handleOpenTextEditor = useCallback((config = {}) => {
279→        editor.setEditable(true)
280→        setEditorLaunchConfig({
281→            ...DEFAULT_EDITOR_LAUNCH_CONFIG,
282→            ...config
283→        });
284→        setShowEditor(true)
285→    }, [editor])
