  1→import React, { useState } from 'react';
  2→import { useQuery } from '@tanstack/react-query';
  3→import { motion, AnimatePresence } from 'framer-motion';
  4→import { getWeeklyRecap } from '../../../API/Api';
  5→import { useAuth } from '../../Context/useAuth';
  6→import './WeeklyRecapCard.css';
  7→
  8→const getWeekKey = () => {
  9→    const now = new Date();
 10→    const day = now.getUTCDay();
 11→    const diff = day === 0 ? 6 : day - 1;
 12→    const monday = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - diff));
 13→    return `recap-dismissed-${monday.toISOString().slice(0, 10)}`;
 14→};
 15→
 16→const formatNumber = (n) => {
 17→    if (!n || n === 0) return '0';
 18→    if (n >= 1000) return `${(n / 1000).toFixed(1)}K`;
 19→    return String(n);
 20→};
 21→
 22→const WeeklyRecapCard = () => {
 23→    const { session } = useAuth();
 24→    const weekKey = getWeekKey();
 25→
 26→    const [dismissed, setDismissed] = useState(() => {
 27→        try { return localStorage.getItem(weekKey) === 'true'; }
 28→        catch { return false; }
 29→    });
 30→    const [expanded, setExpanded] = useState(false);
 31→
 32→    const { data, isLoading } = useQuery({
 33→        queryKey: ['weeklyRecap', session?.access_token],
 34→        queryFn: () => getWeeklyRecap(session?.access_token),
 35→        enabled: !!session?.access_token && !dismissed,
 36→        staleTime: 1000 * 60 * 10,
 37→        refetchOnWindowFocus: false,
 38→    });
 39→
 40→    if (dismissed || isLoading || !data?.recap) return null;
 41→
 42→    const recap = data.recap;
 43→    const personal = recap.personal || {};
 44→    const group = recap.group || {};
 45→
 46→    if (personal.posts_written === 0 && group.total_posts === 0) return null;
 47→
 48→    const handleDismiss = (e) => {
 49→        e.stopPropagation();
 50→        try { localStorage.setItem(weekKey, 'true'); }
 51→        catch { /* no-op */ }
 52→        setDismissed(true);
 53→    };
 54→
 55→    const bestPost = personal.best_post;
 56→    const mostActive = group.most_active_writer;
 57→    const mostReacted = group.most_reacted_post;
 58→
 59→    return (
 60→        <AnimatePresence>
 61→            {!dismissed && (
 62→                <motion.div
 63→                    className="weekly-recap-card"
 64→                    initial={{ opacity: 0, y: -12 }}
 65→                    animate={{ opacity: 1, y: 0 }}
 66→                    exit={{ opacity: 0, y: -20, transition: { duration: 0.25 } }}
 67→                    transition={{ duration: 0.4, ease: 'easeOut' }}
 68→                >
 69→                    <div className="recap-header">
 70→                        <div className="recap-header-left">
 71→                            <svg className="recap-icon" width="18" height="18" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
 72→                                <path d="M9 2H15M12 10V14M12 22C7.02944 22 3 17.9706 3 13C3 8.02944 7.02944 4 12 4C16.9706 4 21 8.02944 21 13C21 17.9706 16.9706 22 12 22Z" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
 73→                            </svg>
 74→                            <span className="recap-label">Your Week</span>
 75→                        </div>
 76→                        <button className="recap-dismiss-btn" onClick={handleDismiss} title="Dismiss">
 77→                            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
 78→                                <path d="M18 6L6 18M6 6L18 18" stroke="currentColor" strokeWidth="2" strokeLinecap="round"/>
 79→                            </svg>
 80→                        </button>
 81→                    </div>
 82→
 83→                    <div className="recap-summary-row" onClick={() => setExpanded((v) => !v)}>
 84→                        <div className="recap-stat">
 85→                            <span className="recap-stat-value">{personal.posts_written || 0}</span>
 86→                            <span className="recap-stat-label">posts</span>
 87→                        </div>
 88→                        <div className="recap-stat-divider" />
 89→                        <div className="recap-stat">
 90→                            <span className="recap-stat-value">{formatNumber(personal.total_words)}</span>
 91→                            <span className="recap-stat-label">words</span>
 92→                        </div>
 93→                        <div className="recap-stat-divider" />
 94→                        <div className="recap-stat">
 95→                            <span className="recap-stat-value">{formatNumber(personal.reactions_received)}</span>
 96→                            <span className="recap-stat-label">reactions</span>
 97→                        </div>
 98→                        <div className="recap-stat-divider" />
 99→                        <div className="recap-stat">
100→                            <span className="recap-stat-value">{formatNumber(personal.views_received)}</span>
101→                            <span className="recap-stat-label">views</span>
102→                        </div>
103→
104→                        <button className={`recap-expand-btn ${expanded ? 'is-expanded' : ''}`}>
105→                            <svg width="14" height="14" viewBox="0 0 24 24" fill="none">
106→                                <path d="M6 9L12 15L18 9" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"/>
107→                            </svg>
108→                        </button>
109→                    </div>
110→
111→                    <AnimatePresence>
112→                        {expanded && (
113→                            <motion.div
114→                                className="recap-details"
115→                                initial={{ height: 0, opacity: 0 }}
116→                                animate={{ height: 'auto', opacity: 1 }}
117→                                exit={{ height: 0, opacity: 0 }}
118→                                transition={{ duration: 0.25, ease: 'easeOut' }}
119→                            >
120→                                <div className="recap-details-inner">
121→                                    {bestPost && bestPost.journal_id && (
122→                                        <div className="recap-detail-section">
123→                                            <span className="recap-detail-heading">Your best post</span>
124→                                            <p className="recap-detail-text">
125→                                                {bestPost.title || 'Untitled'} — {bestPost.reaction_count || 0} reactions
126→                                            </p>
127→                                        </div>
128→                                    )}
129→
130→                                    <div className="recap-detail-section">
131→                                        <span className="recap-detail-heading">Community</span>
132→                                        <p className="recap-detail-text">
133→                                            {group.total_posts || 0} posts written this week
134→                                        </p>
135→                                    </div>
136→
137→                                    {mostActive && mostActive.name && (
138→                                        <div className="recap-detail-section">
139→                                            <span className="recap-detail-heading">Most active writer</span>
140→                                            <div className="recap-detail-user">
141→                                                <img
142→                                                    src={mostActive.avatar || '/assets/profile.jpg'}
143→                                                    alt={mostActive.name}
144→                                                    className="recap-detail-avatar"
145→                                                />
146→                                                <span className="recap-detail-text">
147→                                                    {mostActive.name} — {mostActive.post_count} posts
148→                                                </span>
149→                                            </div>
150→                                        </div>
151→                                    )}
152→
153→                                    {mostReacted && mostReacted.title && (
154→                                        <div className="recap-detail-section">
155→                                            <span className="recap-detail-heading">Most reacted post</span>
156→                                            <div className="recap-detail-user">
157→                                                <img
158→                                                    src={mostReacted.author_avatar || '/assets/profile.jpg'}
159→                                                    alt={mostReacted.author_name}
160→                                                    className="recap-detail-avatar"
161→                                                />
162→                                                <span className="recap-detail-text">
163→                                                    {mostReacted.title} by {mostReacted.author_name} — {mostReacted.reaction_count || 0} reactions
164→                                                </span>
165→                                            </div>
166→                                        </div>
167→                                    )}
168→                                </div>
169→                            </motion.div>
170→                        )}
171→                    </AnimatePresence>
172→                </motion.div>
173→            )}
174→        </AnimatePresence>
175→    );
176→};
177→
178→export default WeeklyRecapCard;
